import numpy as np
from scipy.linalg import expm

class BasicQuantumGenerator:
    def __init__(self, n_qubits: int, n_layers: int = 2):
        self.n_qubits = n_qubits
        self.n_layers = n_layers
        self.dim = 2 ** n_qubits

        self.I = np.eye(2, dtype=complex)
        self.X = np.array([[0, 1], [1, 0]], dtype=complex)
        self.Y = np.array([[0, -1j], [1j, 0]], dtype=complex)
        self.Z = np.array([[1, 0], [0, -1]], dtype=complex)

        self.n_params = 3 * n_qubits * n_layers + (n_qubits - 1) * n_layers
        self.params = np.random.randn(self.n_params) * 0.1

    def _single_gate(self, gate: np.ndarray, qubit: int) -> np.ndarray:
        result = np.array([[1]], dtype=complex)
        for i in range(self.n_qubits):
            result = np.kron(result, gate if i == qubit else self.I)
        return result

    def _rx(self, theta: float, qubit: int) -> np.ndarray:
        gate = expm(-1j * theta / 2 * self.X)
        return self._single_gate(gate, qubit)

    def _ry(self, theta: float, qubit: int) -> np.ndarray:
        gate = expm(-1j * theta / 2 * self.Y)
        return self._single_gate(gate, qubit)

    def _rz(self, theta: float, qubit: int) -> np.ndarray:
        gate = expm(-1j * theta / 2 * self.Z)
        return self._single_gate(gate, qubit)

    def _cnot(self, control: int, target: int) -> np.ndarray:
        cnot = np.zeros((self.dim, self.dim), dtype=complex)
        for i in range(self.dim):
            bits = [(i >> j) & 1 for j in range(self.n_qubits)]
            if bits[control] == 1:
                bits[target] = 1 - bits[target]
            j = sum(b * 2**k for k, b in enumerate(bits))
            cnot[j, i] = 1.0
        return cnot

    def build_circuit(self, params: np.ndarray = None) -> np.ndarray:
        if params is None:
            params = self.params
        U = np.eye(self.dim, dtype=complex)
        idx = 0
        for layer in range(self.n_layers):
            for q in range(self.n_qubits):
                U = self._rx(params[idx], q) @ U; idx += 1
                U = self._ry(params[idx], q) @ U; idx += 1
                U = self._rz(params[idx], q) @ U; idx += 1
            for q in range(self.n_qubits - 1):
                U = self._cnot(q, q + 1) @ U
                idx += 1
        return U

    def generate_state(self, params: np.ndarray = None) -> np.ndarray:
        U = self.build_circuit(params)
        psi0 = np.zeros(self.dim, dtype=complex)
        psi0[0] = 1.0
        return U @ psi0

    def sample(self, n_samples: int) -> np.ndarray:
        psi = self.generate_state()
        probs = np.abs(psi) ** 2
        indices = np.random.choice(self.dim, size=n_samples, p=probs)
        return np.array([[(idx >> i) & 1 for i in range(self.n_qubits)] for idx in indices])

import numpy as np
from scipy.linalg import expm
from typing import Union

class MultiOutputGenerator:
    def __init__(self, n_qubits: int):
        self.n_qubits = n_qubits
        self.dim = 2 ** n_qubits
        self.n_params = 3 * n_qubits
        self.params = np.random.randn(self.n_params) * 0.5

        self.I = np.eye(2, dtype=complex)
        self.X = np.array([[0, 1], [1, 0]], dtype=complex)
        self.Y = np.array([[0, -1j], [1j, 0]], dtype=complex)
        self.Z = np.array([[1, 0], [0, -1]], dtype=complex)

    def _single_gate(self, gate, qubit):
        result = np.array([[1]], dtype=complex)
        for i in range(self.n_qubits):
            result = np.kron(result, gate if i == qubit else self.I)
        return result

    def _generate_base_state(self) -> np.ndarray:
        U = np.eye(self.dim, dtype=complex)
        idx = 0
        for q in range(self.n_qubits):
            U = self._single_gate(expm(-1j * self.params[idx] / 2 * self.X), q) @ U; idx += 1
            U = self._single_gate(expm(-1j * self.params[idx] / 2 * self.Y), q) @ U; idx += 1
            U = self._single_gate(expm(-1j * self.params[idx] / 2 * self.Z), q) @ U; idx += 1
        psi0 = np.zeros(self.dim, dtype=complex)
        psi0[0] = 1.0
        return U @ psi0

    def output_state(self) -> np.ndarray:
        return self._generate_base_state()

    def output_samples(self, n: int) -> np.ndarray:
        psi = self._generate_base_state()
        probs = np.abs(psi) ** 2
        indices = np.random.choice(self.dim, size=n, p=probs)
        return np.array([[(idx >> i) & 1 for i in range(self.n_qubits)] for idx in indices])

    def output_probabilities(self) -> np.ndarray:
        psi = self._generate_base_state()
        return np.abs(psi) ** 2

    def output_features(self) -> np.ndarray:
        psi = self._generate_base_state()
        features = []
        for q in range(self.n_qubits):
            Z_q = self._single_gate(self.Z, q)
            X_q = self._single_gate(self.X, q)
            features.append(np.real(psi.conj() @ Z_q @ psi))
            features.append(np.real(psi.conj() @ X_q @ psi))
        return np.array(features)

    def generate(self, mode: str, n_samples: int = 1) -> Union[np.ndarray, float]:
        if mode == 'state':
            return self.output_state()
        elif mode == 'samples':
            return self.output_samples(n_samples)
        elif mode == 'probabilities':
            return self.output_probabilities()
        elif mode == 'features':
            return self.output_features()
        else:
            raise ValueError(f"Unknown mode: {mode}")
